SELECT (YEAR(?eventTime) AS ?year) WHERE {
  ?game wdt:P31 wd:Q384820;  # American football game
        rdfs:label ?gameLabel;
        wdt:P585 ?eventTime;
        wdt:P1545 ?winner.
  FILTER (LANG(?gameLabel) = 'en')
  FILTER (CONTAINS(LCASE(?gameLabel), 'army-navy'))
  ?winner rdfs:label ?winnerLabel.
  FILTER (LANG(?winnerLabel) = 'en')
  FILTER (CONTAINS(LCASE(?winnerLabel), 'army'))
} ORDER BY DESC(?eventTime) LIMIT 1

